"""CLI for the review tool."""

from __future__ import annotations

import builtins
import json
import sqlite3
import sys
from pathlib import Path
from typing import Optional

import click
import uvicorn

from review_tool.app import create_app
from review_tool.config import FILE_REPO_MAP
from review_tool.db import (
    get_db_sync,
    init_db_sync,
    insert_finding_sync,
    insert_safe_sync,
)
from review_tool.logging_setup import setup_logging
from review_tool.parser import parse_validation_file


@click.group()
def cli():
    """Charm bug finding review tool."""
    setup_logging()


@cli.command()
@click.option("--port", default=8000, help="Port to serve on.")
@click.option("--host", default="0.0.0.0", help="Host to bind to.")
def serve(port: int, host: str):
    """Start the local web server."""
    app = create_app()
    uvicorn.run(app, host=host, port=port)


@cli.command()
def tui():
    """Start the terminal UI (Textual)."""
    from review_tool.tui import run_tui

    run_tui()


@cli.command(name="import")
@click.argument("file_path", type=click.Path(exists=True))
@click.option(
    "--round", "round_num", type=int, required=True, help="Validation round number."
)
@click.option("--repo", default=None, help="Override repository name.")
def import_file(file_path: str, round_num: int, repo: Optional[str]):
    """Import findings from a markdown validation file."""
    path = Path(file_path)
    init_db_sync()

    if not repo:
        repo = FILE_REPO_MAP.get(path.name)

    findings, safe = parse_validation_file(path, round_num, repo)
    conn = get_db_sync()

    inserted = 0
    skipped = 0
    for f in findings:
        result = insert_finding_sync(conn, f)
        if result > 0:
            inserted += 1
        else:
            skipped += 1

    safe_count = 0
    for s in safe:
        insert_safe_sync(conn, s)
        safe_count += 1

    # Log import
    try:
        conn.execute(
            "INSERT INTO import_log (source_file, findings_count, safe_count) VALUES (?, ?, ?)",
            [str(path), inserted, safe_count],
        )
    except sqlite3.IntegrityError:
        conn.execute(
            "UPDATE import_log SET imported_at = datetime('now'), findings_count = ?, safe_count = ? WHERE source_file = ?",
            [inserted, safe_count, str(path)],
        )

    conn.commit()
    conn.close()

    click.echo(
        f"Imported {inserted} findings, {skipped} skipped (duplicates), {safe_count} confirmed safe entries."
    )


@cli.command(name="import-all")
def import_all():
    """Import all existing validation files."""
    data_dir = Path(__file__).resolve().parent.parent.parent / "data"
    init_db_sync()

    files_rounds = {
        "skill_validation_grafana.md": 1,
        "skill_validation_kafka.md": 1,
        "skill_validation_discourse.md": 2,
        "skill_validation_hydra.md": 2,
        "skill_validation_opensearch.md": 2,
        "skill_validation_sdcore_amf.md": 2,
        "skill_validation_traefik.md": 3,
        "skill_validation_temporal.md": 3,
        "skill_validation_vault.md": 3,
        "skill_validation_mongodb.md": 3,
        "skill_validation_postgresql.md": 4,
        "skill_validation_indico.md": 4,
        "skill_validation_prometheus.md": 4,
        "skill_validation_kratos.md": 4,
    }

    total_inserted = 0
    total_safe = 0
    for filename, round_num in files_rounds.items():
        path = data_dir / filename
        if not path.exists():
            click.echo(f"  Skipping {filename}: not found")
            continue

        repo = FILE_REPO_MAP.get(filename)
        findings, safe = parse_validation_file(path, round_num, repo)
        conn = get_db_sync()

        inserted = 0
        for f in findings:
            result = insert_finding_sync(conn, f)
            if result > 0:
                inserted += 1

        safe_count = 0
        for s in safe:
            insert_safe_sync(conn, s)
            safe_count += 1

        try:
            conn.execute(
                "INSERT INTO import_log (source_file, findings_count, safe_count) VALUES (?, ?, ?)",
                [str(path), inserted, safe_count],
            )
        except sqlite3.IntegrityError:
            conn.execute(
                "UPDATE import_log SET imported_at = datetime('now'), findings_count = ?, safe_count = ? WHERE source_file = ?",
                [inserted, safe_count, str(path)],
            )

        conn.commit()
        conn.close()

        click.echo(f"  {filename}: {inserted} findings, {safe_count} safe")
        total_inserted += inserted
        total_safe += safe_count

    click.echo(
        f"\nTotal: {total_inserted} findings, {total_safe} confirmed safe entries."
    )


@cli.command(name="list")
@click.option("--severity", default=None, help="Filter by severity.")
@click.option("--status", default=None, help="Filter by review status.")
@click.option("--repo", default=None, help="Filter by repository.")
@click.option("--round", "round_num", type=int, default=None, help="Filter by round.")
def list_findings(
    severity: Optional[str],
    status: Optional[str],
    repo: Optional[str],
    round_num: Optional[int],
):
    """List findings in a table."""
    init_db_sync()
    conn = get_db_sync()

    query = "SELECT * FROM findings WHERE 1=1"
    params: builtins.list[str | int] = []
    if severity:
        query += " AND severity = ?"
        params.append(severity)
    if status:
        query += " AND review_status = ?"
        params.append(status)
    if repo:
        query += " AND repo = ?"
        params.append(repo)
    if round_num is not None:
        query += " AND round = ?"
        params.append(round_num)
    query += " ORDER BY round, repo, bug_id"

    cursor = conn.execute(query, params)
    rows = cursor.fetchall()
    conn.close()

    if not rows:
        click.echo("No findings match the filters.")
        return

    # Print table
    click.echo(
        f"{'ID':>4} {'Sev':>8} {'Bug':>8} {'Repo':<25} {'R':>2} {'Status':<14} Title"
    )
    click.echo("-" * 100)
    for r in rows:
        status_icon = {"pending": ".", "reviewed": "+", "false_positive": "x"}.get(
            r["review_status"], "?"
        )
        click.echo(
            f"{r['id']:>4} {r['severity']:>8} {r['bug_id']:>8} {r['repo']:<25} {r['round']:>2} "
            f"{status_icon} {r['review_status']:<12} {r['title'][:50]}"
        )
    click.echo(f"\n{len(rows)} findings.")


@cli.command()
@click.argument("finding_id", type=int)
def show(finding_id: int):
    """Show a single finding in detail."""
    init_db_sync()
    conn = get_db_sync()
    cursor = conn.execute("SELECT * FROM findings WHERE id = ?", [finding_id])
    row = cursor.fetchone()
    conn.close()

    if not row:
        click.echo(f"Finding {finding_id} not found.")
        sys.exit(1)

    click.echo(
        f"[{row['bug_id']}] {row['category']} -- {row['title']} ({row['severity']})"
    )
    click.echo(
        f"Repo: {row['repo']} | Charm: {row['charm_name']} | Round: {row['round']}"
    )
    click.echo(f"Location: {row['location']}")
    click.echo(f"Pattern: {row['pattern']}")
    click.echo(f"Status: {row['review_status']}")
    if row["reviewer_notes"]:
        click.echo(f"Notes: {row['reviewer_notes']}")
    click.echo(f"\n--- Issue ---\n{row['issue']}")
    click.echo(f"\n--- Impact ---\n{row['impact']}")
    click.echo(f"\n--- Evidence ---\n{row['evidence']}")
    click.echo(f"\n--- Recommended Fix ---\n{row['recommended_fix']}")
    if row["historical_precedent"]:
        click.echo(f"\n--- Historical Precedent ---\n{row['historical_precedent']}")


@cli.command()
@click.argument("finding_id", type=int)
@click.option(
    "--status",
    required=True,
    type=click.Choice(["reviewed", "false_positive", "pending"]),
)
@click.option("--notes", default=None, help="Reviewer notes.")
def review(finding_id: int, status: str, notes: Optional[str]):
    """Update the review status of a finding."""
    init_db_sync()
    conn = get_db_sync()

    cursor = conn.execute("SELECT id FROM findings WHERE id = ?", [finding_id])
    if not cursor.fetchone():
        click.echo(f"Finding {finding_id} not found.")
        sys.exit(1)

    sets = ["review_status = ?", "updated_at = datetime('now')"]
    params: builtins.list[str | int] = [status]
    if status in ("reviewed", "false_positive"):
        sets.append("reviewed_at = datetime('now')")
    if notes is not None:
        sets.append("reviewer_notes = ?")
        params.append(notes)
    params.append(finding_id)

    conn.execute(f"UPDATE findings SET {', '.join(sets)} WHERE id = ?", params)
    conn.commit()
    conn.close()
    click.echo(f"Finding {finding_id} marked as '{status}'.")


@cli.command()
def stats():
    """Show summary statistics."""
    init_db_sync()
    conn = get_db_sync()

    total = conn.execute("SELECT COUNT(*) FROM findings").fetchone()[0]
    if total == 0:
        click.echo("No findings in the database.")
        conn.close()
        return

    pending = conn.execute(
        "SELECT COUNT(*) FROM findings WHERE review_status = 'pending'"
    ).fetchone()[0]
    reviewed = conn.execute(
        "SELECT COUNT(*) FROM findings WHERE review_status = 'reviewed'"
    ).fetchone()[0]
    fp = conn.execute(
        "SELECT COUNT(*) FROM findings WHERE review_status = 'false_positive'"
    ).fetchone()[0]

    click.echo(
        f"Total: {total} | Reviewed: {reviewed} | False Positive: {fp} | Pending: {pending}"
    )
    click.echo(
        f"Progress: {reviewed + fp}/{total} ({100 * (reviewed + fp) / total:.0f}%)"
    )

    click.echo("\nBy Severity:")
    for row in conn.execute(
        "SELECT severity, COUNT(*) FROM findings GROUP BY severity "
        "ORDER BY CASE severity WHEN 'Critical' THEN 1 WHEN 'High' THEN 2 WHEN 'Medium' THEN 3 ELSE 4 END"
    ):
        click.echo(f"  {row[0]}: {row[1]}")

    click.echo("\nBy Repository:")
    for row in conn.execute(
        "SELECT repo, COUNT(*) FROM findings GROUP BY repo ORDER BY repo"
    ):
        click.echo(f"  {row[0]}: {row[1]}")

    click.echo("\nBy Round:")
    for row in conn.execute(
        "SELECT round, COUNT(*) FROM findings GROUP BY round ORDER BY round"
    ):
        click.echo(f"  Round {row[0]}: {row[1]}")

    conn.close()


@cli.command()
@click.option(
    "--output", "-o", default=None, type=click.Path(), help="Output file path."
)
def export(output: Optional[str]):
    """Export all findings as JSON."""
    init_db_sync()
    conn = get_db_sync()

    cursor = conn.execute("SELECT * FROM findings ORDER BY round, repo, bug_id")
    rows = [dict(r) for r in cursor.fetchall()]
    conn.close()

    data = json.dumps({"findings": rows, "count": len(rows)}, indent=2)

    if output:
        Path(output).write_text(data)
        click.echo(f"Exported {len(rows)} findings to {output}")
    else:
        click.echo(data)

"""HTML page routes for the web UI."""

from __future__ import annotations

from typing import Optional

from fastapi import APIRouter, Query, Request
from fastapi.responses import HTMLResponse, RedirectResponse
from pygments import highlight
from pygments.formatters import HtmlFormatter  # type: ignore[attr-defined]
from pygments.lexers import PythonLexer  # type: ignore[attr-defined]

from review_tool import db
from review_tool.config import DB_PATH

router = APIRouter(tags=["pages"])

_python_lexer = PythonLexer()
_html_formatter = HtmlFormatter(nowrap=False, cssclass="highlight")


def highlight_python(code: str) -> str:
    """Syntax-highlight Python code."""
    return highlight(code, _python_lexer, _html_formatter)


@router.get("/", response_class=HTMLResponse)
async def dashboard(request: Request):
    conn = await db.get_db(DB_PATH)
    try:
        stats = await db.get_stats(conn)
        return request.app.state.templates.TemplateResponse(
            "index.html",
            {"request": request, "stats": stats},
        )
    finally:
        await conn.close()


@router.get("/findings", response_class=HTMLResponse)
async def findings_page(
    request: Request,
    severity: Optional[str] = Query(None),
    status: Optional[str] = Query(None),
    repo: Optional[str] = Query(None),
    round: Optional[str] = Query(None),
):
    # Treat empty strings from form selects as None
    severity = severity or None
    status = status or None
    repo = repo or None
    round_int = int(round) if round else None

    conn = await db.get_db(DB_PATH)
    try:
        findings = await db.get_findings(conn, severity, status, repo, round_int)
        stats = await db.get_stats(conn)

        # Get unique repos and rounds for filter dropdowns
        all_findings = await db.get_findings(conn)
        repos = sorted({f["repo"] for f in all_findings})
        rounds = sorted({f["round"] for f in all_findings})

        # If htmx request for just the list partial
        if request.headers.get("HX-Target") == "findings-list":
            return request.app.state.templates.TemplateResponse(
                "partials/findings_list.html",
                {"request": request, "findings": findings},
            )

        return request.app.state.templates.TemplateResponse(
            "findings.html",
            {
                "request": request,
                "findings": findings,
                "stats": stats,
                "repos": repos,
                "rounds": rounds,
                "current_severity": severity or "",
                "current_status": status or "",
                "current_repo": repo or "",
                "current_round": round_int or "",
            },
        )
    finally:
        await conn.close()


@router.get("/findings/{finding_id}", response_class=HTMLResponse)
async def finding_detail(request: Request, finding_id: int):
    conn = await db.get_db(DB_PATH)
    try:
        finding = await db.get_finding(conn, finding_id)
        if not finding:
            return HTMLResponse("<p>Finding not found</p>", status_code=404)

        # Highlight code blocks
        evidence_html = (
            highlight_python(finding["evidence"]) if finding["evidence"] else ""
        )
        fix_html = (
            highlight_python(finding["recommended_fix"])
            if finding["recommended_fix"]
            else ""
        )

        return request.app.state.templates.TemplateResponse(
            "partials/finding_detail.html",
            {
                "request": request,
                "finding": finding,
                "evidence_html": evidence_html,
                "fix_html": fix_html,
            },
        )
    finally:
        await conn.close()


@router.patch("/findings/{finding_id}", response_class=HTMLResponse)
async def update_finding_html(request: Request, finding_id: int):
    conn = await db.get_db(DB_PATH)
    try:
        form = await request.form()
        update_data = {}
        if "review_status" in form:
            update_data["review_status"] = form["review_status"]
        if "reviewer_notes" in form:
            update_data["reviewer_notes"] = form["reviewer_notes"]

        finding = await db.update_finding(conn, finding_id, update_data)
        if not finding:
            return HTMLResponse("<p>Finding not found</p>", status_code=404)

        # Return updated row partial (template uses `f` as the loop variable)
        return request.app.state.templates.TemplateResponse(
            "partials/finding_row.html",
            {"request": request, "f": finding},
        )
    finally:
        await conn.close()


@router.get("/findings/{finding_id}/next-unreviewed")
async def next_unreviewed(finding_id: int):
    conn = await db.get_db(DB_PATH)
    try:
        next_id = await db.get_next_unreviewed(conn, finding_id)
        if next_id:
            return RedirectResponse(url=f"/findings/{next_id}", status_code=303)
        return HTMLResponse("<p>All findings have been reviewed!</p>")
    finally:
        await conn.close()

"""Textual TUI for the review tool."""

from __future__ import annotations

from textual import work
from textual.app import App, ComposeResult
from textual.binding import Binding
from textual.containers import Horizontal, Vertical, VerticalScroll
from textual.widgets import (
    DataTable,
    Footer,
    Header,
    Label,
    OptionList,
    Select,
    Static,
    TextArea,
)

from review_tool.config import DB_PATH
from review_tool.db import (
    get_db_sync,
    get_finding_sync,
    get_findings_sync,
    get_stats_sync,
    init_db_sync,
    update_finding_sync,
)

SEVERITY_COLOURS = {
    "Critical": "white on dark_red",
    "High": "white on rgb(180,80,0)",
    "Medium": "black on yellow",
    "Low": "white on blue",
}

STATUS_ICONS = {
    "pending": "[dim]·[/]",
    "reviewed": "[green]✓[/]",
    "false_positive": "[red]✗[/]",
}


class StatsBar(Static):
    """Top bar showing review progress."""

    def update_stats(self, stats: dict) -> None:
        done = stats["reviewed"] + stats["false_positive"]
        total = stats["total"]
        pct = f"{100 * done / total:.0f}%" if total else "–"
        self.update(
            f" [bold]{done}[/]/{total} reviewed ({pct})  "
            f"[green]{stats['reviewed']} reviewed[/]  "
            f"[red]{stats['false_positive']} false positive[/]  "
            f"[dim]{stats['pending']} pending[/]"
        )


class FindingDetail(VerticalScroll):
    """Right-hand pane showing a single finding's details."""

    def compose(self) -> ComposeResult:
        yield Label("Select a finding from the table.", id="detail-placeholder")

    def show_finding(self, f: dict) -> None:
        self.remove_children()

        sev_style = SEVERITY_COLOURS.get(f["severity"], "")
        status_icon = STATUS_ICONS.get(f["review_status"], "?")

        lines = [
            f"[bold][{f['bug_id']}] {f['title']}[/bold]",
            f"[{sev_style}] {f['severity']} [/]  {status_icon} {f['review_status']}",
            "",
            f"[bold]Category:[/] {f['category']}",
            f"[bold]Repo:[/] {f['repo']}  [bold]Round:[/] {f['round']}",
            f"[bold]Location:[/] {f['location']}",
            f"[bold]Pattern:[/] {f['pattern']}",
        ]
        if f.get("reviewer_notes"):
            lines.extend(["", f"[bold]Reviewer notes:[/] {f['reviewer_notes']}"])

        self.mount(Static("\n".join(lines), id="detail-header"))

        sections = [
            ("Issue", f["issue"]),
            ("Impact", f["impact"]),
            ("Evidence", f["evidence"]),
            ("Recommended Fix", f["recommended_fix"]),
        ]
        if f.get("historical_precedent"):
            sections.append(("Historical Precedent", f["historical_precedent"]))

        for title, body in sections:
            self.mount(Static(f"\n[bold underline]{title}[/]"))
            self.mount(Static(body))

    def show_empty(self) -> None:
        self.remove_children()
        self.mount(Label("Select a finding from the table.", id="detail-placeholder"))


class NotesInput(TextArea):
    """Text area for reviewer notes."""


class ReviewApp(App):
    """Charm Bug Review TUI."""

    CSS = """
    #stats-bar {
        dock: top;
        height: 1;
        background: $surface;
        padding: 0 1;
    }

    #main {
        height: 1fr;
    }

    #filters {
        dock: top;
        height: 3;
        padding: 0 1;
        layout: horizontal;
    }

    #filters Select {
        width: 1fr;
        margin: 0 1 0 0;
    }

    #table-pane {
        width: 40%;
        border-right: solid $primary-background;
    }

    #detail-pane {
        width: 60%;
        padding: 0 1;
    }

    #notes-area {
        height: 4;
        margin: 1 0;
    }

    #review-buttons {
        height: 3;
        padding: 0 1;
        dock: bottom;
    }

    #review-buttons Label {
        margin: 0 2 0 0;
    }

    DataTable {
        height: 1fr;
    }

    FindingDetail {
        height: 1fr;
    }
    """

    BINDINGS = [
        Binding("r", "mark_reviewed", "Reviewed", show=True),
        Binding("f", "mark_false_positive", "False Positive", show=True),
        Binding("p", "mark_pending", "Pending", show=True),
        Binding("n", "focus_notes", "Notes", show=True),
        Binding("d", "focus_table", "Findings", show=True),
        Binding("q", "quit", "Quit", show=True),
    ]

    TITLE = "Charm Bug Review"

    def __init__(self) -> None:
        super().__init__()
        self._findings: list[dict] = []
        self._current_finding: dict | None = None
        self._filter_severity: str | None = None
        self._filter_status: str | None = None
        self._filter_repo: str | None = None

    def compose(self) -> ComposeResult:
        yield Header()
        yield StatsBar(id="stats-bar")
        yield Horizontal(
            Select(
                [(s, s) for s in ("Critical", "High", "Medium", "Low")],
                prompt="All Severities",
                id="filter-severity",
                allow_blank=True,
            ),
            Select(
                [
                    ("Pending", "pending"),
                    ("Reviewed", "reviewed"),
                    ("False Positive", "false_positive"),
                ],
                prompt="All Statuses",
                id="filter-status",
                allow_blank=True,
            ),
            Select([], prompt="All Repos", id="filter-repo", allow_blank=True),
            id="filters",
        )
        yield Horizontal(
            Vertical(
                DataTable(id="findings-table", cursor_type="row"),
                id="table-pane",
            ),
            Vertical(
                FindingDetail(id="detail-pane"),
                NotesInput(id="notes-area"),
                id="right-pane",
            ),
            id="main",
        )
        yield Footer()

    def on_mount(self) -> None:
        table = self.query_one("#findings-table", DataTable)
        table.add_columns("ID", "Sev", "St", "Repo", "R", "Title")
        self._load_data()

    @work(thread=True)
    def _load_data(self) -> None:
        init_db_sync(DB_PATH)
        conn = get_db_sync(DB_PATH)
        stats = get_stats_sync(conn)
        all_findings = get_findings_sync(conn)
        repos = sorted({f["repo"] for f in all_findings})

        findings = get_findings_sync(
            conn,
            severity=self._filter_severity,
            status=self._filter_status,
            repo=self._filter_repo,
        )
        conn.close()

        self.call_from_thread(self._apply_data, stats, findings, repos)

    def _apply_data(
        self, stats: dict, findings: list[dict], repos: list[str]
    ) -> None:
        self.query_one("#stats-bar", StatsBar).update_stats(stats)

        # Populate repo filter if empty
        repo_select = self.query_one("#filter-repo", Select)
        if not repo_select._options:
            repo_select.set_options([(r, r) for r in repos])

        self._findings = findings
        table = self.query_one("#findings-table", DataTable)
        table.clear()
        for f in findings:
            sev = f["severity"]
            st_icon = {"pending": "·", "reviewed": "✓", "false_positive": "✗"}.get(
                f["review_status"], "?"
            )
            table.add_row(
                str(f["id"]),
                sev,
                st_icon,
                f["repo"],
                str(f["round"]),
                f["title"][:60],
                key=str(f["id"]),
            )

    def on_data_table_row_selected(self, event: DataTable.RowSelected) -> None:
        if event.row_key and event.row_key.value:
            self._show_finding(int(event.row_key.value))

    def on_data_table_row_highlighted(
        self, event: DataTable.RowHighlighted
    ) -> None:
        if event.row_key and event.row_key.value:
            self._show_finding(int(event.row_key.value))

    @work(thread=True)
    def _show_finding(self, finding_id: int) -> None:
        conn = get_db_sync(DB_PATH)
        finding = get_finding_sync(conn, finding_id)
        conn.close()
        if finding:
            self.call_from_thread(self._apply_finding, finding)

    def _apply_finding(self, finding: dict) -> None:
        self._current_finding = finding
        self.query_one("#detail-pane", FindingDetail).show_finding(finding)
        notes_area = self.query_one("#notes-area", NotesInput)
        notes_area.load_text(finding.get("reviewer_notes", ""))

    def on_select_changed(self, event: Select.Changed) -> None:
        sel_id = event.select.id
        val = event.value if event.value != Select.BLANK else None
        if sel_id == "filter-severity":
            self._filter_severity = val
        elif sel_id == "filter-status":
