        sev_style = SEVERITY_COLOURS.get(f["severity"], "")
        status_icon = STATUS_ICONS.get(f["review_status"], "?")

        lines = [
            f"[bold][{f['bug_id']}] {f['title']}[/bold]",
            f"[{sev_style}] {f['severity']} [/]  {status_icon} {f['review_status']}",
