        height: 4;
        margin: 1 0;
    }

    #review-buttons {
        height: 3;
        padding: 0 1;
        dock: bottom;
    }

    #review-buttons Label {
        margin: 0 2 0 0;
    }

    DataTable {
        height: 1fr;
    }

    FindingDetail {
        height: 1fr;
    }
