}


class StatsBar(Static):
    """Top bar showing review progress."""

    def update_stats(self, stats: dict) -> None:
        done = stats["reviewed"] + stats["false_positive"]
        total = stats["total"]
        pct = f"{100 * done / total:.0f}%" if total else "–"
